    // --- PURE FUNCTION: Axiomatic Reasoning Core ---
    
    /// PURE FUNCTION: Finds ALL Axiom matches in memory for a given query.
    /// Input: Query, and a reference to the memory store.
    /// Output: A vector of potential ReasoningResults (one for each match).
    pub fn pure_find_all_axiom_matches(
        memory: &CduStore,
        query: &CausalQuery,
    ) -> Vec<ReasoningResult> {
        let mut matches = Vec::new();
        const BASE_COMPUTE: u64 = 10; 

        for cdu in memory.memory.values() {
            if let CausalDataUnit::Axiom(axiom_cdu) = cdu {
                // Simple Test: Check if the query question contains the axiom content.
                if query.question.contains(&axiom_cdu.content) {
                    let solution = CausalDataUnit::Axiom(axiom_cdu.clone());
                    
                    matches.push(ReasoningResult {
                        solution_data: solution,
                        confidence: 0.99,
                        compute_cost: BASE_COMPUTE,
                        source_path: ReasoningPath::Cascading, // Tagged as the first step of Cascading
                    });
                }
            }
        }
        matches
    }
    
